import subprocess
from pathlib import Path
import os

def generate_requirements_txt():
    """
    Generate a requirements.txt file with hashes.
    
    This function uses pip freeze to generate a list of dependencies and their versions,
    then uses pip install --generate-hashes to add the hashes for each dependency.
    """
    # Get the current working directory
    cwd = Path.cwd()
    
    # Create a new requirements.txt file in the root of the project
    req_file = cwd / 'requirements.txt'
    
    # Use subprocess to run the pip commands
    subprocess.run(['pip', 'freeze', '--local', '--all-requires'], stdout=open(req_file, 'w'))
    subprocess.run(['pip', 'install', '--generate-hashes', '-r', str(req_file)])

def generate_poetry_lock():
    """
    Generate a Poetry lock file.
    
    This function uses poetry install to generate the lock file.
    """
    # Get the current working directory
    cwd = Path.cwd()
    
    # Create a new pyproject.toml file in the root of the project if it doesn't exist
    pyproj_file = cwd / 'pyproject.toml'
    if not pyproj_file.exists():
        with open(pyproj_file, 'w') as f:
            f.write('[tool.poetry]\n')
    
    # Use subprocess to run the poetry command
    subprocess.run(['poetry', 'install'])

def update_dependencies():
    """
    Update dependencies in requirements.txt or Poetry lock file.
    
    This function uses pip freeze to generate a list of dependencies and their versions,
    then updates the requirements.txt file with these dependencies. If a Poetry project,
    it generates a new lock file using poetry install.
    """
    # Get the current working directory
    cwd = Path.cwd()
    
    # Check if we're in a Poetry project
    pyproj_file = cwd / 'pyproject.toml'
    if pyproj_file.exists():
        generate_poetry_lock()
    else:
        generate_requirements_txt()

# Usage example
if __name__ == '__main__':
    update_dependencies()